const result = [];
const items = $input.all();
if (items.length === 0) return result;

// 1. Verificamos si n8n usó la fila de letras (A, B, C) como nombres de las columnas
const primerFila = items[0].json;
const claves = Object.keys(primerFila);
const usaCabeceras = claves.includes("A") && claves.includes("B") && claves.includes("C");

if (usaCabeceras) {
  // CASO A: Las letras A, B, C... son los nombres de las columnas
  for (const item of items) {
    const fila = item.json;

    // Buscamos la letra de la fila (A-Z)
    let letraFila = fila[""] || fila["Column 1"] || fila["0"];
    if (!letraFila || letraFila.length !== 1) {
       for (const val of Object.values(fila)) {
         if (typeof val === 'string' && val.trim().length === 1 && val.match(/^[A-Z]$/i)) {
           letraFila = val; break;
         }
       }
    }

    if (!letraFila || typeof letraFila !== 'string' || letraFila.trim().length !== 1) continue;
    letraFila = letraFila.trim().toUpperCase();

    // Recorremos las columnas para armar los pares
    for (const [columna, palabra] of Object.entries(fila)) {
      if (columna.length === 1 && columna.match(/^[A-Z]$/i)) {
         if (palabra && typeof palabra === 'string' && palabra.trim() !== "") {
            result.push({
              json: {
                par: letraFila + columna.toUpperCase(),
                palabra: palabra.trim()
              }
            });
         }
      }
    }
  }
} else {
  // CASO B: Las letras A, B, C... están mezcladas dentro de las celdas como valores
  const matriz = items.map(item => Object.values(item.json));

  let indiceCabecera = -1;
  for (let i = 0; i < matriz.length; i++) {
    if (matriz[i].includes("A") && matriz[i].includes("B") && matriz[i].includes("C")) {
      indiceCabecera = i; break;
    }
  }

  if (indiceCabecera !== -1) {
    const letrasColumnas = matriz[indiceCabecera];

    for (let i = indiceCabecera + 1; i < matriz.length; i++) {
      const fila = matriz[i];
      let letraFila = fila.find(val => typeof val === 'string' && val.trim().length === 1 && val.match(/^[A-Z]$/i));

      if (letraFila) {
        letraFila = letraFila.trim().toUpperCase();
        for (let j = 0; j < fila.length; j++) {
          const letraColumna = letrasColumnas[j];
          const palabra = fila[j];

          if (letraColumna && typeof letraColumna === 'string' && letraColumna.trim().length === 1 && letraColumna.match(/^[A-Z]$/i)) {
            if (palabra && typeof palabra === 'string' && palabra.trim() !== "" && palabra.trim().toUpperCase() !== letraFila) {
              result.push({
                json: {
                  par: letraFila + letraColumna.trim().toUpperCase(),
                  palabra: palabra.trim()
                }
              });
            }
          }
        }
      }
    }
  }
}

return result;

// Juntamos los 15 pares en una sola lista
const listaPares = $input.all().map(item => item.json);

// Obtenemos tu Chat ID del primer nodo (¡Cambia el nombre si el tuyo es diferente!)
const chatId = $('Telegram Trigger').first().json.message.chat.id;

return [{
  json: {
    chat_id: chatId,
    estado: "entrenando",
    pares: listaPares,          // Guardamos la lista completa
    pregunta_actual: 0,         // Empezamos en el índice 0 (pregunta 1)
    aciertos: 0,
    primer_par: listaPares[0].par // Extraemos la primera letra para preguntártela ahora mismo
  }
}];

// 1. Obtenemos lo que escribiste en Telegram
const mensajeUsuario = $('Telegram Trigger').first().json.message.text.trim().toLowerCase();

// 2. Obtenemos los datos de tu sesión de la base de datos
const sesion = $input.first().json;

// 3. ESCUDO: Si no hay sesión o ya está inactiva
if (!sesion || !sesion.pares || sesion.estado !== "entrenando") {
  return [{ 
    json: { 
      error: true, 
      mensaje_telegram: "No tienes un entrenamiento activo en este momento. 😅\n\nEscribe /empezar para iniciar una nueva ronda." 
    } 
  }];
}

// ----------------------------------------------------
// 🌟 NUEVO: DETECCIÓN DE CANCELACIÓN
// ----------------------------------------------------
if (mensajeUsuario === "/cancelar") {
  return [{
    json: {
      error: false,
      id_sesion: sesion.id, 
      chat_id: sesion.chat_id,
      estado: "inactivo", // <-- ¡Magia! Cerramos la sesión
      pregunta_actual: sesion.pregunta_actual,
      aciertos: sesion.aciertos,
      errores: sesion.errores || [], 
      mensaje_telegram: "🛑 **Entrenamiento cancelado.**\n\nNo te preocupes, el progreso hasta aquí quedó guardado. Escribe /empezar cuando estés listo para una nueva ronda."
    }
  }];
}
// ----------------------------------------------------

// 4. Si no cancelaste, evaluamos tu respuesta
const pares = sesion.pares;
let indice = sesion.pregunta_actual;
let aciertos = sesion.aciertos;
let errores = sesion.errores || []; 

const parActual = pares[indice];
const palabraCorrecta = parActual.palabra.trim().toLowerCase();

let esCorrecto = (mensajeUsuario === palabraCorrecta);

if (esCorrecto) {
  aciertos++; 
} else {
  errores.push(parActual.par);
}

// 5. Preparamos el mensaje
let textoRespuesta = esCorrecto
  ? `✅ ¡Correcto! Era **${parActual.palabra}**.\n\n`
  : `❌ ¡Fallaste! La palabra para **${parActual.par}** era **${parActual.palabra}**.\n\n`;

// 6. Avanzamos
indice++; 
let estado = sesion.estado;

if (indice < pares.length) {
  textoRespuesta += `🧠 **Pregunta ${indice + 1}/${pares.length}:**\n¿Qué palabra es: **${pares[indice].par}**?`;
} else {
  estado = "inactivo";
  textoRespuesta += `🎉 **¡Entrenamiento finalizado!**\nAcertaste ${aciertos} de ${pares.length}. ¡Sigue practicando tu BLD!\n\nEscribe /empezar para jugar de nuevo.`;
}

// 7. Entregamos los datos al nodo de Supabase
return [{
  json: {
    error: false,
    id_sesion: sesion.id, 
    chat_id: sesion.chat_id,
    estado: estado,
    pregunta_actual: indice,
    aciertos: aciertos,
    errores: errores, 
    mensaje_telegram: textoRespuesta
  }
}];
